1	export type Cell = [number, number];
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	const fromKey = (key: string): Cell => key.split(",").map(Number) as Cell;
5	
6	const NEIGHBOR_OFFSETS: Cell[] = [
7	  [-1, -1], [-1, 0], [-1, 1],
8	  [ 0, -1],          [ 0, 1],
9	  [ 1, -1], [ 1, 0], [ 1, 1],
10	];
11	
12	const survives = (isAlive: boolean, neighbors: number): boolean =>
13	  neighbors === 3 || (isAlive && neighbors === 2);
14	
15	const countNeighbors = (cells: Cell[]): Map<string, number> => {
16	  const counts = new Map<string, number>();
17	  for (const [x, y] of cells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const key = toKey([x + dx, y + dy]);
20	      counts.set(key, (counts.get(key) ?? 0) + 1);
21	    }
22	  }
23	  return counts;
24	};
25	
26	export function nextGeneration(cells: Cell[]): Cell[] {
27	  const liveKeys = new Set(cells.map(toKey));
28	  const neighborCounts = countNeighbors(cells);
29	
30	  return Array.from(neighborCounts)
31	    .filter(([key, count]) => survives(liveKeys.has(key), count))
32	    .map(([key]) => fromKey(key));
33	}
