1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should preserve a block (still life: 2x2 square)", () => {
15	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(input);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(input));
19	  });
20	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
21	    const input: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(input);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(expected));
26	  });
27	  it("should kill a live cell with 4+ neighbors (overpopulation)", () => {
28	    // Live cell at (1,1) with 4 neighbors: (0,0),(2,0),(0,2),(2,2)
29	    const input: [number, number][] = [[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]];
30	    const result = nextGeneration(input);
31	    expect(result).not.toContainEqual([1, 1]);
32	  });
33	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
34	    // L-shape: (1,1) is dead but has 3 live neighbors → birth
35	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
36	    const result = nextGeneration(input);
37	    expect(result).toContainEqual([1, 1]);
38	  });
39	  it.todo("should handle negative coordinates");
40	});
